class AppDelegate: UIResponder, UIApplicationDelegate {
    func application(_ app: UIApplication, open url: URL, options: [UIApplication.OpenURLOptionsKey : Any] = [:]) -> Bool {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true), let queryItems = components.queryItems else { return false }
        
        var promoCode: String?
        var discountPercentage: Int?
        
        for item in queryItems {
            switch item.name {
            case "code":
                promoCode = item.value
            case "discount":
                if let value = Int(item.value) {
                    discountPercentage = value
                }
            default:
                break
            }
        }
        
        guard let promoCode = promoCode, let discountPercentage = discountPercentage else { return false }
        
        // Validate promo code and discount percentage
