            print("Invalid promo code or discount percentage")
            return false
        }
        
        // Apply promo code and discount to user account
        let defaults = UserDefaults.standard
        defaults.set(promoCode, forKey: "promoCode")
        defaults.set(discountPercentage, forKey: "discountPercentage")
        
        return true
    }
}

